 56→/**
 57→ * This is a temporary class to make the PostListViewModel more manageable. Please feel free to refactor it any way
 58→ * you see fit.
 59→ */
 60→@Suppress("LongParameterList")
 61→class PostActionHandler(
 62→    private val dispatcher: Dispatcher,
 63→    private val site: SiteModel,
 64→    private val postStore: PostStore,
 65→    private val postListDialogHelper: PostListDialogHelper,
 66→    private val doesPostHaveUnhandledConflict: (PostModel) -> Boolean,
 67→    private val hasUnhandledAutoSave: (PostModel) -> Boolean,
 68→    private val triggerPostListAction: (PostListAction) -> Unit,
 69→    private val triggerPostUploadAction: (PostUploadAction) -> Unit,
 70→    private val triggerPublishAction: (PostModel) -> Unit,
 71→    private val invalidateList: () -> Unit,
 72→    private val checkNetworkConnection: () -> Boolean,
 73→    private val showSnackbar: (SnackbarMessageHolder) -> Unit,
 74→    private val showToast: (ToastMessageHolder) -> Unit,
 75→    private val triggerPreviewStateUpdate: (PostListRemotePreviewState, PostInfoType) -> Unit,
 76→    private val copyPost: (SiteModel, PostModel, Boolean) -> Unit
 77→) {
 78→    private val criticalPostActionTracker = CriticalPostActionTracker(onStateChanged = {
 79→        invalidateList.invoke()
 80→    })
 81→
 82→    fun handlePostButton(buttonType: PostListButtonType, post: PostModel, hasAutoSave: Boolean) {
 83→        when (buttonType) {
 84→            BUTTON_EDIT -> editPostButtonAction(site, post)
 85→            BUTTON_RETRY -> triggerPostListAction.invoke(RetryUpload(post))
 86→            BUTTON_MOVE_TO_DRAFT -> {
 87→                moveTrashedPostToDraft(post)
 88→            }
 89→            BUTTON_PUBLISH -> {
 90→                triggerPublishAction.invoke(post)
 91→            }
 92→            BUTTON_SYNC -> {
 93→                postListDialogHelper.showSyncScheduledPostConfirmationDialog(post)
 94→            }
 95→            BUTTON_SUBMIT -> publishPost(post.id)
 96→            BUTTON_VIEW -> triggerPostListAction.invoke(ViewPost(site, post))
 97→            BUTTON_PREVIEW -> triggerPostListAction.invoke(
 98→                PreviewPost(
 99→                    site = site,
100→                    post = post,
101→                    triggerPreviewStateUpdate = triggerPreviewStateUpdate,
102→                    showToast = showToast,
103→                    messageMediaUploading = ToastMessageHolder(
104→                        R.string.editor_toast_uploading_please_wait,
105→                        Duration.SHORT
106→                    )
107→                )
108→            )
109→            BUTTON_STATS -> triggerPostListAction.invoke(ViewStats(site, post))
110→            BUTTON_TRASH -> {
111→                when {
112→                    post.isLocallyChanged -> {
113→                        postListDialogHelper.showTrashPostWithLocalChangesConfirmationDialog(post)
114→                    }
115→                    hasAutoSave -> {
116→                        postListDialogHelper.showTrashPostWithUnsavedChangesConfirmationDialog(post)
117→                    }
118→                    else -> trashPost(post)
119→                }
120→            }
121→            BUTTON_COPY -> copyPost(site, post, true)
122→            BUTTON_COPY_URL -> triggerPostListAction.invoke(copyUrlAction(post))
123→            BUTTON_DELETE, BUTTON_DELETE_PERMANENTLY -> {
124→                postListDialogHelper.showDeletePostConfirmationDialog(post)
125→            }
126→            BUTTON_CANCEL_PENDING_AUTO_UPLOAD -> {
127→                cancelPendingAutoUpload(post)
128→            }
129→            BUTTON_SHOW_MOVE_TRASHED_POST_TO_DRAFT_DIALOG -> {
130→                postListDialogHelper.showMoveTrashedPostToDraftDialog(post)
131→            }
132→            BUTTON_MORE -> {
133→            } // do nothing - ui will show a popup window
134→            BUTTON_PROMOTE_WITH_BLAZE -> {
135→                triggerPostListAction.invoke(PostListAction.ShowPromoteWithBlaze(post))
136→            }
137→            BUTTON_COMMENTS -> {} // todo: implement
138→        }
139→    }
140→
141→    private fun copyUrlAction(post: PostModel) = PostListAction.CopyUrl(
142→        site = site,
143→        post = post,
144→        showSnackbar = showSnackbar,
145→        messageSuccess = SnackbarMessageHolder(
146→            UiStringRes(R.string.post_link_copied_to_clipboard),
147→            duration = Snackbar.LENGTH_SHORT,
148→            isImportant = false
149→        ),
150→        messageError = SnackbarMessageHolder(
151→            UiStringRes(R.string.error_copy_to_clipboard),
152→            duration = Snackbar.LENGTH_SHORT,
153→            isImportant = false
154→        )
155→    )
156→
157→    private fun cancelPendingAutoUpload(post: PostModel) {
158→        val msgRes = UploadUtils.cancelPendingAutoUpload(post, dispatcher)
159→        showSnackbar.invoke(SnackbarMessageHolder(UiStringRes(msgRes)))
160→    }
161→
162→    fun newPost() {
163→        triggerPostListAction(PostListAction.NewPost(site))
164→    }
165→
166→    fun newStoryPost() {
167→        triggerPostListAction(PostListAction.NewStoryPost(site))
168→    }
169→
170→    fun handleEditPostResult(data: Intent?) {
171→        val localPostId = data?.getIntExtra(EditPostActivity.EXTRA_POST_LOCAL_ID, 0)
172→        if (localPostId == null || localPostId == 0) {
173→            return
174→        }
175→        val post = postStore.getPostByLocalPostId(localPostId)
176→        if (post != null) {
177→            triggerPostUploadAction(EditPostResult(site, post, data) { publishPost(localPostId) })
178→        }
179→    }
180→
181→    fun handleRemotePreview(localPostId: Int, remotePreviewType: RemotePreviewType) {
182→        val post = postStore.getPostByLocalPostId(localPostId)
183→        if (post != null) {
184→            triggerPostListAction.invoke(PostListAction.RemotePreviewPost(site, post, remotePreviewType))
185→        }
186→    }
187→
188→    fun publishPost(localPostId: Int) {
189→        val post = postStore.getPostByLocalPostId(localPostId)
190→        if (post != null) {
191→            triggerPostUploadAction.invoke(PublishPost(dispatcher, site, post))
192→        }
193→    }
194→
195→    fun publishPost(post: PostModel) {
196→        triggerPostUploadAction.invoke(PublishPost(dispatcher, site, post))
197→    }
198→
199→    fun resolveConflictsAndEditPost(localPostId: Int) {
200→        val post = postStore.getPostByLocalPostId(localPostId)
201→        if (post != null) {
202→            performChecksAndEdit(site, post)
203→        }
204→    }
205→
206→    fun moveTrashedPostToDraft(localPostId: Int) {
207→        val post = postStore.getPostByLocalPostId(localPostId)
208→        if (post != null) {
209→            moveTrashedPostToDraft(post)
210→        }
211→    }
212→
213→    private fun moveTrashedPostToDraft(post: PostModel) {
214→        /*
215→         * We need network connection to move a post to remote draft. We can technically move it to the local drafts
216→         * but that'll leave the trashed post in the remote which can be confusing.
217→         */
218→        if (!checkNetworkConnection.invoke()) {
219→            return
220→        }
221→        post.setStatus(DRAFT.toString())
222→        dispatcher.dispatch(PostActionBuilder.newPushPostAction(RemotePostPayload(post, site)))
223→
224→        val localPostId = LocalId(post.id)
225→        criticalPostActionTracker.add(localPostId, MOVING_POST_TO_DRAFT)
226→
227→        val snackBarHolder = SnackbarMessageHolder(
228→            message = UiStringRes(R.string.post_moving_to_draft),
229→            onDismissAction = {
230→                criticalPostActionTracker.remove(localPostId, MOVING_POST_TO_DRAFT)
231→            }
232→        )
233→        showSnackbar.invoke(snackBarHolder)
234→    }
235→
236→    private fun editPostButtonAction(site: SiteModel, post: PostModel) = performChecksAndEdit(site, post)
237→
238→    private fun performChecksAndEdit(site: SiteModel, post: PostModel) {
239→        // first of all, check whether this post is in Conflicted state with a more recent remote version
240→        if (doesPostHaveUnhandledConflict.invoke(post)) {
241→            postListDialogHelper.showConflictedPostResolutionDialog(post)
242→            return
243→        }
244→
245→        // Then check if an autosave revision is available
246→        if (hasUnhandledAutoSave.invoke(post)) {
247→            postListDialogHelper.showAutoSaveRevisionDialog(post)
248→            return
249→        }
250→
251→        editPost(site, post)
252→    }
253→
254→    private fun editPost(site: SiteModel, post: PostModel) {
255→        if (UploadService.isPostUploadingOrQueued(post)) {
256→            // If the post is uploading media, allow the media to continue uploading, but don't upload the
257→            // post itself when they finish (since we're about to edit it again)
258→            UploadService.cancelQueuedPostUpload(post)
259→        }
260→        triggerPostListAction.invoke(PostListAction.EditPost(site, post, loadAutoSaveRevision = false))
261→    }
262→
263→    fun deletePost(localPostId: Int) {
264→        // If post doesn't exist, nothing else to do
265→        val post = postStore.getPostByLocalPostId(localPostId) ?: return
266→        criticalPostActionTracker.add(LocalId(post.id), DELETING_POST)
267→
268→        when {
269→            post.isLocalDraft -> {
270→                val pushId = PendingDraftsNotificationsUtils.makePendingDraftNotificationId(post.id)
271→                triggerPostListAction(DismissPendingNotification(pushId))
272→                dispatcher.dispatch(PostActionBuilder.newRemovePostAction(post))
273→            }
274→            else -> {
275→                dispatcher.dispatch(PostActionBuilder.newDeletePostAction(RemotePostPayload(post, site)))
276→            }
277→        }
278→    }
279→
280→    /**
281→     * This function handles a post being deleted and removed. Since deleting remote posts will trigger both delete
282→     * and remove actions we only want to remove the critical action when the post is actually successfully removed.
283→     *
284→     * It's possible to separate these into two methods that handles delete and remove. However, the fact that they
285→     * follow the same approach and the tricky nature of delete action makes combining the actions like so makes our
286→     * expectations clearer.
287→     */
288→    fun handlePostDeletedOrRemoved(localPostId: LocalId, isRemoved: Boolean, isError: Boolean) {
289→        if (criticalPostActionTracker.get(localPostId) != DELETING_POST) {
290→            /*
291→             * This is an unexpected action and either it has already been handled or another critical action has
292→             * been performed. In either case, safest action is to just ignore it.
293→             */
294→            return
295→        }
296→        if (isError) {
297→            showToast.invoke(ToastMessageHolder(R.string.error_deleting_post, Duration.SHORT))
298→        }
299→        if (isRemoved) {
300→            criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = DELETING_POST)
301→        }
302→    }
303→
304→    fun trashPostWithLocalChanges(localPostId: Int) {
305→        // If post doesn't exist, nothing else to do
306→        val post = postStore.getPostByLocalPostId(localPostId) ?: return
307→        trashPost(post, true)
308→    }
309→
310→    fun trashPostWithUnsavedChanges(localPostId: Int) {
311→        val post = postStore.getPostByLocalPostId(localPostId) ?: return
312→        trashPost(post)
313→    }
314→
315→    private fun trashPost(post: PostModel, hasLocalChanges: Boolean = false) {
316→        // We need network connection to trash a post
317→        if (!checkNetworkConnection()) {
318→            return
319→        }
320→        val criticalPostAction = if (hasLocalChanges) {
321→            TRASHING_POST_WITH_LOCAL_CHANGES
322→        } else {
323→            TRASHING_POST
324→        }
325→
326→        showSnackbar.invoke(SnackbarMessageHolder(UiStringRes(R.string.post_trashing)))
327→        criticalPostActionTracker.add(localPostId = LocalId(post.id), criticalPostAction = criticalPostAction)
328→
329→        triggerPostUploadAction.invoke(CancelPostAndMediaUpload(post))
330→        dispatcher.dispatch(PostActionBuilder.newDeletePostAction(RemotePostPayload(post, site)))
331→    }
332→
333→    @Suppress("UseCheckOrError")
334→    fun handlePostTrashed(localPostId: LocalId, isError: Boolean) {
335→        val criticalAction = criticalPostActionTracker.get(localPostId)
336→        if (criticalAction != TRASHING_POST && criticalAction != TRASHING_POST_WITH_LOCAL_CHANGES) {
337→            /*
338→             * This is an unexpected action and either it has already been handled or another critical action has
339→             * been performed. In either case, safest action is to just ignore it.
340→             */
341→            return
342→        }
343→        criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = criticalAction)
344→        if (isError) {
345→            showToast.invoke(ToastMessageHolder(R.string.error_deleting_post, Duration.SHORT))
346→        } else {
347→            val snackBarHolder = when (criticalAction) {
348→                TRASHING_POST -> SnackbarMessageHolder(
349→                    message = UiStringRes(R.string.post_trashed),
350→                    buttonTitle = UiStringRes(R.string.undo),
351→                    buttonAction = {
352→                        val post = postStore.getPostByLocalPostId(localPostId.value)
353→                        if (post != null) {
354→                            restorePost(post)
355→                        }
356→                    }
357→                )
358→                TRASHING_POST_WITH_LOCAL_CHANGES -> SnackbarMessageHolder(message = UiStringRes(R.string.post_trashed))
359→                else -> throw IllegalStateException("Unexpected action in handlePostTrashed(): $criticalAction")
360→            }
361→            showSnackbar.invoke(snackBarHolder)
362→        }
363→    }
364→
365→    private fun restorePost(post: PostModel) {
366→        // We need network connection to restore a post
367→        if (!checkNetworkConnection.invoke()) {
368→            return
369→        }
370→        showSnackbar.invoke(SnackbarMessageHolder(message = UiStringRes(R.string.post_restoring)))
371→        criticalPostActionTracker.add(localPostId = LocalId(post.id), criticalPostAction = RESTORING_POST)
372→        dispatcher.dispatch(PostActionBuilder.newRestorePostAction(RemotePostPayload(post, site)))
373→    }
374→
375→    fun handlePostRestored(localPostId: LocalId, isError: Boolean) {
376→        if (criticalPostActionTracker.get(localPostId) != RESTORING_POST) {
377→            /*
378→             * This is an unexpected action and either it has already been handled or another critical action has
379→             * been performed. In either case, safest action is to just ignore it.
380→             */
381→            return
382→        }
383→        criticalPostActionTracker.remove(localPostId = localPostId, criticalPostAction = RESTORING_POST)
384→        if (isError) {
385→            showToast.invoke(ToastMessageHolder(R.string.error_restoring_post, Duration.SHORT))
386→        } else {
387→            showSnackbar.invoke(SnackbarMessageHolder(message = UiStringRes(R.string.post_restored)))
388→        }
389→    }
390→
391→    fun isPerformingCriticalAction(localPostId: LocalId): Boolean {
392→        return criticalPostActionTracker.contains(localPostId)
393→    }
394→}
